package com.veetu.vadagai.payment;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import java.math.BigDecimal;import java.util.UUID;public interface PaymentRepository extends JpaRepository<Payment,UUID>{@Query("select coalesce(sum(p.amount),0) from Payment p where p.status='SUCCESS' and p.deleted=false") BigDecimal totalRevenue();@Query("select coalesce(sum(p.amount),0) from Payment p where p.status in ('PENDING','CREATED') and p.deleted=false") BigDecimal pendingDues();Page<Payment> findByPayerIdAndDeletedFalse(UUID payerId,Pageable pageable);}
